class Solution:
    def replaceElements(self, arr):
        n = len(arr)
        res = []
        for i in range(n):
            if i == n - 1:
                res.append(-1)
            else:
                res.append(max(arr[i + 1:]))
        return res

solutions.python:
class Solution:
    def replaceElements(self, arr):
        best = -1
        for i in range(len(arr) - 1, -1, -1):
            cur = arr[i]
            arr[i] = best
            if cur > best:
                best = cur
        return arr

